require __DIR__.'/../includes/bootstrap.php';require_auth();if(!brands_schema_ready())redirect((user()['role']??'')==='admin'?'../upgrade-brands-imports.php':'../dashboard.php');$companies=manageable_companies((int)user()['id']);if(!$companies){flash('error','You must manage an approved company before creating a brand.');redirect('../dashboard.php');}$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();try{$companyId=(int)($_POST['company_id']??0);$allowed=array_column($companies,'id');if(!in_array($companyId,$allowed))throw new RuntimeException('Choose a company you manage.');$name=trim($_POST['name']??'');if($name==='')throw new RuntimeException('Brand name is required.');$website=trim($_POST['website']??'');if($website!==''&&!filter_var($website,FILTER_VALIDATE_URL))throw new RuntimeException('Enter a complete website URL.');$email=trim($_POST['public_email']??'');if($email!==''&&!filter_var($email,FILTER_VALIDATE_EMAIL))throw new RuntimeException('Enter a valid public email.');db()->beginTransaction();$slug=brand_slug($name);$s=db()->prepare("INSERT INTO brands(company_id,name,slug,short_description,description,website,public_email,category,founded_year,status,submitted_by) VALUES(?,?,?,?,?,?,?,?,?,'pending',?)");$s->execute([$companyId,$name,$slug,trim($_POST['short_description']??''),trim($_POST['description']??''),$website,$email,trim($_POST['category']??''),((int)($_POST['founded_year']??0))?:null,(int)user()['id']]);$id=(int)db()->lastInsertId();db()->prepare("INSERT INTO brand_members(brand_id,user_id,position_title,brand_role,status) VALUES(?,?,?,'pending_manager','pending')")->execute([$id,(int)user()['id'],trim($_POST['position_title']??'Brand Manager')]);db()->prepare("INSERT INTO brand_approval_history(brand_id,action,notes,acted_by) VALUES(?,'submitted',?,?)")->execute([$id,'Submitted under an approved company.',(int)user()['id']]);db()->commit();$logo=save_uploaded_image('logo','brands/logos',$id);$banner=save_uploaded_image('banner','brands/banners',$id);if($logo||$banner){$parts=[];$args=[];if($logo){$parts[]='logo_path=?';$args[]=$logo;}if($banner){$parts[]='banner_path=?';$args[]=$banner;}$args[]=$id;db()->prepare('UPDATE brands SET '.implode(',',$parts).' WHERE id=?')->execute($args);}flash('success','Brand submitted for administrator approval.');redirect('dashboard.php?id='.$id);}catch(Throwable $e){if(db()->inTransaction())db()->rollBack();$error=$e->getMessage();}}
app_header('Create Brand');?><section class="dashboard-hero"><p class="eyebrow">BRAND SUBMISSION</p><h1>Create a Brand</h1><p>Add a brand beneath a company you manage.</p></section><?php if($error):?><div class="alert error"><?=e($error)?></div><?php endif?><form method="post" enctype="multipart/form-data" class="profile-form"><?=csrf_field()?><section class="app-card form-grid"><label>Parent company<select name="company_id" required><?php foreach($companies as $c):?><option value="<?=(int)$c['id']?>"><?=e($c['name'])?></option><?php endforeach?></select></label><label>Brand name<input name="name" required></label><label>Category<input name="category"></label><label>Founded year<input type="number" name="founded_year" min="1500" max="<?=date('Y')?>"></label><label class="full">Short description<input name="short_description" maxlength="280"></label><label class="full">Description<textarea name="description"></textarea></label><label>Website<input type="url" name="website" placeholder="https://"></label><label>Public email<input type="email" name="public_email"></label><label>Your brand position<input name="position_title" placeholder="Brand Manager"></label><label>Logo<input type="file" name="logo" accept="image/*"></label><label>Banner<input type="file" name="banner" accept="image/*"></label></section><div class="form-actions"><a class="button ghost" href="index.php">Cancel</a><button class="button primary">Submit Brand</button></div></form><?php app_footer();
